class Solution:
    def insert(self, intervals, newInterval):
        out = []
        start, end = newInterval
        placed = False
        for a, b in intervals:
            if b < start: out.append([a, b])
            elif end < a:
                if not placed: out.append([start, end]); placed = True
                out.append([a, b])
            else:
                start, end = min(start, a), max(end, b)
        if not placed: out.append([start, end])
        return out
